PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX wd: <http://www.wikidata.org/entity/>
SELECT(FLOOR(SUM(?duration * 60) / 60) AS ?hours)(SUM(?duration * 60) -(FLOOR(SUM(?duration * 60) / 60) * 60) AS ?minutes) WHERE {
  ?movie wdt:P179 wd:Q216930 .
  ?movie wdt:P2047 ?duration .
}
